import React, { useState } from 'react';

function SignUp() {
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });

  const handleSignUp = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('http://127.0.0.1:5000/api/signup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      const result = await response.json();
      if (response.ok) {
        alert("Pendaftaran Berhasil! Silakan Login.");
        window.location.href = "/"; 
      } else {
        alert(result.message);
      }
    } catch (error) {
      alert("Gagal terhubung ke server backend!");
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h1 style={styles.title}>Sign up</h1>
        <p style={styles.subtitle}>Daftar akun admin baru</p>
        <form onSubmit={handleSignUp}>
          <div style={styles.inputGroup}>
            <label style={styles.label}>Nama Lengkap</label>
            <input type="text" placeholder="Contoh: Ferdi" style={styles.input}
              onChange={(e) => setFormData({...formData, name: e.target.value})} required />
          </div>
          <div style={styles.inputGroup}>
            <label style={styles.label}>Email</label>
            <input type="email" placeholder="Contoh: admin@gmail.com" style={styles.input}
              onChange={(e) => setFormData({...formData, email: e.target.value})} required />
          </div>
          <div style={styles.inputGroup}>
            <label style={styles.label}>Password</label>
            <input type="password" placeholder="Masukkan password" style={styles.input}
              onChange={(e) => setFormData({...formData, password: e.target.value})} required />
          </div>
          <button type="submit" style={styles.button}>Sign up</button>
        </form>
        <p style={styles.footer}>Sudah punya akun? <a href="/">Login</a></p>
      </div>
    </div>
  );
}

const styles = {
  container: { display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', backgroundColor: '#f9f9f9' },
  card: { padding: '40px', borderRadius: '10px', backgroundColor: '#fff', boxShadow: '0 4px 20px rgba(0,0,0,0.1)', width: '100%', maxWidth: '400px' },
  title: { fontSize: '28px', textAlign: 'center', marginBottom: '10px' },
  subtitle: { textAlign: 'center', color: '#666', marginBottom: '20px' },
  inputGroup: { marginBottom: '15px' },
  label: { display: 'block', fontSize: '14px', marginBottom: '5px', fontWeight: 'bold' },
  input: { width: '100%', padding: '10px 0', border: 'none', borderBottom: '1px solid #ccc', outline: 'none' },
  button: { width: '100%', padding: '12px', backgroundColor: '#007bff', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer', marginTop: '20px' },
  footer: { textAlign: 'center', marginTop: '15px', fontSize: '14px' }
};

export default SignUp;
